SellItemConfig = {}
SellItemConfig.items = {}

function SellItemConfig:init(config)
    for k, v in pairs(config) do
        local item = {}
        item.id = tonumber(v.UniqueId)
        item.itemId = tonumber(v.ItemId)
        item.itemMeta = tonumber(v.ItemMeta)
        item.money = tonumber(v.Money)

        table.insert(self.items, item)
    end
end

function SellItemConfig:getSellItem(id, meta)
    for k, v in pairs(self.items) do
        if v.itemMeta == -1 then
            if v.itemId == id then
                return v
            end
        else
            if v.itemId == id and v.itemMeta == meta then
                return v
            end
        end
    end
    return nil
end

function SellItemConfig:getMoneyByItemId(id)
    for k, v in pairs(self.items) do
        if v.itemId == id then
            return v.money
        end
    end
    return nil
end



return SellItemConfig